import sys

def process_sentence(sentence):
    # Remove any distractor part after '|'
    sentence = sentence.split('|')[0].strip()
    parts = sentence.split()
    name = parts[0]
    if 'has' in parts:
        N = int(parts[2])
        M = int(parts[5])
        return N + M
    elif 'had' in parts:
        N = int(parts[2])
        M = int(parts[5])
        if M <= N:
            return N - M
        else:
            return 'INVALID'
    elif 'gives' in parts:
        N = int(parts[2])
        M = int(parts[6])
        if M <= N:
            return N - M
        else:
            return 'INVALID'
    return 'INVALID'

if __name__ == '__main__':
    input = sys.stdin.read().strip().split('\n')
    t = int(input[0])
    results = []
    for i in range(1, t + 1):
        result = process_sentence(input[i])
        results.append(result)
    print('\n'.join(map(str, results)))
